VALUES
  ('social-worker-moex-01331', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「防禦性實務工作者」（defensivepractitioner）的敘述，下列何者錯誤？', '["將注意力放在官僚程序的落實而非服務對象的最佳利益", "「照本宣科」完成法律或組織規定的職責以規避責任", "社會工作者的職責被限縮在完成對機構的義務", "社會工作者準備好承擔風險與道德責難"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01332', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '某社會工作師對一夫妻進行婚姻諮商：先生的賭博問題嚴重，導致財務困難和夫妻關係失衡。後 來經社會工作師轉介，先生參加戒賭課程，並向社會工作師及妻子提到參加戒賭課程對他有多大 的幫助。然而，某天先生致電社會工作師，並向其表示其實自己沒有參加戒賭課程，且沉迷賭博 問題愈加嚴重，自己也深感無助。最後希望社會工作師不要跟妻子說這事。下列敘述何者正確？', '["義務論者主張，社會工作師應揭露隱私資料，以保護妻子免於受欺騙並面對先生的謊言是較好的", "行為的效益主義者主張，社會工作師應保留隱私資訊才不會影響先生對社會工作師的信任", "規則的效益主義者主張，社會工作師應違背案主的意願，揭露先生的隱私權", "倫理利己主義者主張，社會工作師應有權力選擇結束這個專業關係；或對妻子揭露資訊，以保 護她免於被欺瞞"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01333', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '杜鵑窩協會正在執行一個協助精神病友社區居住方案，但是在過程中遭遇社區民眾的反彈。若專 家學者在過程中所關切的焦點為「違背社區民眾意願而執行社區居住方案所帶來的影響」，這位 專家學者是屬於何種學派？', '["目的論", "義務論", "規則的效益主義", "目的效益主義"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01334', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於傳統觀點的專業界線敘述，下列何者正確？', '["案主若視社會工作者為其專業協助者以外的角色，將有利於治療關係的發展，以及充分運用社 會工作者與案主的關係", "社會工作者必須和案主的關係保持一個清晰而不模糊的界線", "雙重關係是可以完全避免的", "當專業關係變成雙重關係時，社會工作者的權力繼續保持並受專業行為規範的約束"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01335', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '離婚結束兩個人之間的法律關係，但家庭成員的心理情緒與社會層面均會受影響。評估離婚家庭', '["兒童不同的年齡與性別對離婚反應基本相同", "父母離婚後對兒童生活穩定的影響， 如轉學", "特別注意家長的經濟狀況", "為了避免衝突，離婚的配偶應避免接觸無監護權的子女 ⑤當成人陷入離婚引起的情緒時，家庭網絡可否提供子女穩定的生活照顧與支持"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01336', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者在發生災難後，協助災民處理殯葬問題、緊急安置、災民照顧安排，和救災物資管理 等，是屬於那個救援階段的工作？', '["緊急救援期", "短期安置期", "長期安置期", "災後重建期"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01337', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「威脅傷害對方家人、朋友、寵物，破壞個人物品，剝奪個人的金錢、睡眠，語言上的辱罵或行 為上的騷擾」，為那一類型之親密關係暴力？', '["身體暴力", "情緒暴力", "性暴力", "經濟控制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01338', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '直轄市、縣（市）主管機關對於依少年事件處理法交付安置輔導或感化教育結束、停止或免除， 或經交付轉介輔導之兒童、少年及其家庭，應予追蹤輔導：', '["至少1年", "至少2年", "至少3年", "至少4年"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01339', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '增權取向（empowermentapproach）對青少年偏差行為問題成因的敘述，下列何者正確？', '["青少年偏差行為是受身心急遽發展失衡所致", "青少年偏差行為是受環境資源不均與制度結構機會的剝奪所致", "青少年偏差行為是自我認同不足所致", "青少年偏差行為是道德認知發展未臻成熟所致"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01340', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關我國新制身心障礙鑑定所依據的國際健康功能與身心障礙分類系統（ICF），下列敘述何者 正確？', '["相信障礙是特殊族群的特殊經驗，而非人人都可能經歷的", "認為障礙者需要他人照顧，應由專家給予治療，並協助其心理調適", "整合醫療與社會模式，並強調「生理心理社會」（bio-psycho-social）策略", "主張社會工作者應扮演專家的角色協助障礙者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
